 1	import type { FC, ReactNode } from 'react';
 2	
 3	import { Label } from '@patternfly/react-core';
 4	
 5	import { TableCell, type TableCellProps } from './TableCell';
 6	
 7	/**
 8	 * A component that displays a table cell, with an optional label.
 9	 *
10	 * @param {TableLabelCellProps} props - The props for the component.
11	 * @returns {ReactElement} The rendered TableLabelCell component.
12	 */
13	export const TableLabelCell: FC<TableLabelCellProps> = ({
14	  children,
15	  hasLabel = false,
16	  isWrap = false,
17	  label,
18	  labelColor = 'grey',
19	}) => {
20	  const labels = Array.isArray(label) ? label : [label];
21	  const labelColors = Array.isArray(labelColor) ? labelColor : labels.map(() => labelColor);
22	
23	  return (
24	    <TableCell isWrap={isWrap}>
25	      {children}
26	      {hasLabel &&
27	        labels.map((_, i) => (
28	          <Label
29	            key={i}
30	            isCompact
31	            color={labelColors[i]}
32	            className="forklift-table__flex-cell-label"
33	          >
34	            {labels[i]}
35	          </Label>
36	        ))}
37	    </TableCell>
38	  );
39	};
40	
41	type Colors = 'blue' | 'cyan' | 'green' | 'orange' | 'purple' | 'red' | 'grey';
42	export type TableLabelCellProps = {
43	  hasLabel?: boolean;
44	  label?: ReactNode | ReactNode[];
45	  labelColor?: Colors | Colors[];
46	  isWrap?: boolean;
47	} & TableCellProps;

